  ('SCIENCE-G4-PSE-SCO82', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Propose solutions to challenges arising from natural forces.', 3199, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO83', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Seek feedback from community leaders on preparation and mitigation strategies.', 3200, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
