  ('SCIENCE-G4-PSE-SCO85', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Observe and identify building features that increase resilience to natural earth processes.', 3202, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO86', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Design a simple earth-resistant structure using everyday materials.', 3203, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO87', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Design a simple structure suitable for a tsunami-prone area.', 3204, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO88', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Develop concern for persons affected by natural earth processes.', 3205, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO89', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Appreciate the importance of resilient structures.', 3206, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO90', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Appreciate the importance of responding to early warning signals.', 3207, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO91', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Value practices that support flood prevention.', 3208, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G4-PSE-SCO92', 'SCIENCE-G4-PSE-ELO4', 'SCIENCE-G4-PSE', 'SCIENCE', 'science', 'G4', '4', 'Processes that Shape the Earth ', 'Recognize the importance of teamwork and collaboration in mitigating natural earth processes.', 3209, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO1', 'SS-G4-HCT-ELO1', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Describe the basic economic and social life of the Indigenous people of the Caribbean before contact with Europeans', 3210, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO2', 'SS-G4-HCT-ELO1', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Chart the location where Indigenous people of the Caribbean were living before contact with Europeans.', 3211, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO3', 'SS-G4-HCT-ELO1', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Appreciate that the Indigenous people of the Caribbean had flourishing societies and economies before contact with Europeans.', 3212, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO4', 'SS-G4-HCT-ELO2', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Identify the European groups that came to the Caribbean in the 15th - 16th centuries and state reasons why they came.', 3213, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO5', 'SS-G4-HCT-ELO2', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Categorise the impact of Europeans’ colonisation on the lifestyle of Indigenous people and Europeans in the Caribbean.', 3214, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO6', 'SS-G4-HCT-ELO2', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Develop an awareness that colonisation had many lasting negative consequences for the Indigenous people of the Caribbean.', 3215, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO7', 'SS-G4-HCT-ELO3', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Identify ways in which Indigenous people resisted European colonisation ', 3216, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO8', 'SS-G4-HCT-ELO3', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Explain the reasons why Indigenous peoples resisted colonisation.', 3217, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO9', 'SS-G4-HCT-ELO3', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Appreciate that Indigenous people actively resisted colonisation.', 3218, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO10', 'SS-G4-HCT-ELO4', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Describe aspects of Indigenous people’s lifestyle practised in the Caribbean today.', 3219, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO11', 'SS-G4-HCT-ELO4', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Locate where the Indigenous people of the Lesser Antilles are living today.', 3220, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-HCT-SCO12', 'SS-G4-HCT-ELO4', 'SS-G4-HCT', 'SS', 'social-studies', 'G4', '4', 'Historical and Cultural Thinking', 'Appreciate that the Indigenous people of the Caribbean continue to have unique and vibrant lifestyles', 3221, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO1', 'SS-G4-ST-ELO1', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Locate the island where you live on maps / globes using lines of latitude and longitude', 3222, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO2', 'SS-G4-ST-ELO1', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Describe our island’s location in relation to the wider Caribbean', 3223, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO3', 'SS-G4-ST-ELO1', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Appreciate the advantages of maps and technology such as Google Earth in locating and describing our island’s geography', 3224, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO4', 'SS-G4-ST-ELO2', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Identify the geographic divisions of the country', 3225, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO5', 'SS-G4-ST-ELO2', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Label a map of the country to identify the geographic divisions', 3226, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO6', 'SS-G4-ST-ELO3', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Define and classify the major physical features of our island', 3227, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO7', 'SS-G4-ST-ELO3', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Observe the differences between various land and water features of our island ', 3228, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO8', 'SS-G4-ST-ELO4', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Describe the climate of our island(s)', 3229, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO9', 'SS-G4-ST-ELO4', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Investigate the changes in climate', 3230, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO10', 'SS-G4-ST-ELO4', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Appreciate that our climate has risks for our population.', 3231, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO11', 'SS-G4-ST-ELO5', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Identify significant weather events that have impacted the natural environment', 3232, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO12', 'SS-G4-ST-ELO5', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Investigate the consequences of recent weather events on the built environment of your country', 3233, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO13', 'SS-G4-ST-ELO5', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Appreciate the need to prepare for climate emergencies and actions that can be taken to lessen the effects of natural forces', 3234, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO14', 'SS-G4-ST-ELO6', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Determine the scope and nature of the areas of your country that are parklands or natural reserves', 3235, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO15', 'SS-G4-ST-ELO6', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Locate and describe the features and characteristics of these parklands or reserves', 3236, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO16', 'SS-G4-ST-ELO6', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Appreciate the purpose of these areas and their significance for preserving flora, fauna, and human existence', 3237, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO17', 'SS-G4-ST-ELO7', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Identify the sources and status of our island’s fresh water.', 3238, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO18', 'SS-G4-ST-ELO7', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Determine the ways that you can help conserve and protect our local water sources', 3239, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO19', 'SS-G4-ST-ELO7', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Appreciate the importance of protecting our fresh water sources', 3240, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO20', 'SS-G4-ST-ELO8', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Explain the impact of human activity on the natural environment', 3241, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO21', 'SS-G4-ST-ELO8', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Gather information from multiple sources to explain the impact of human activity on the natural environment', 3242, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-ST-SCO22', 'SS-G4-ST-ELO8', 'SS-G4-ST', 'SS', 'social-studies', 'G4', '4', 'Spatial Thinking', 'Appreciate that we can reduce the negative effects of human activity on our natural environment', 3243, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO1', 'SS-G4-CP-ELO1', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Identify ways in which communication technology has evolved over time.', 3244, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
