  ('SS-G4-CP-SCO5', 'SS-G4-CP-ELO2', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Investigate challenges in local transportation and predict possible future solutions to the transportation issues.', 3248, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
