  ('SS-G4-CP-SCO7', 'SS-G4-CP-ELO3', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'List some of the major events in the political evolution of your country-territory', 3250, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
