  ('SS-G4-CP-SCO10', 'SS-G4-CP-ELO4', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Describe the type of government system in your country', 3253, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO11', 'SS-G4-CP-ELO4', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Appreciate that the government system and structure in the country is influenced by the history of colonization.', 3254, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO12', 'SS-G4-CP-ELO4', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Investigate and outline the various purposes and responsibilities of your government', 3255, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO13', 'SS-G4-CP-ELO5', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Explain what democracy is and share some examples', 3256, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO14', 'SS-G4-CP-ELO5', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Demonstrate ways in which we can actively participate in our democracy', 3257, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO15', 'SS-G4-CP-ELO5', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Appreciate the value of democracy for protecting our individual rights and freedom', 3258, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO16', 'SS-G4-CP-ELO6', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Identify that there are political constituencies in our country.', 3259, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO17', 'SS-G4-CP-ELO6', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Appreciate the importance of these constituencies for ensuring local representation', 3260, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO18', 'SS-G4-CP-ELO6', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Locate the boundaries of the political constituency to which you belong.', 3261, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO19', 'SS-G4-CP-ELO7', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Identify key figures who have made significant contributions to our national development.', 3262, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO20', 'SS-G4-CP-ELO7', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Develop criteria to justify determining who is a national hero/heroine.', 3263, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO21', 'SS-G4-CP-ELO7', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Appreciate the contribution of key figures to our national development', 3264, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO22', 'SS-G4-CP-ELO8', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Explain our responsibilities to contribute to the development of the country', 3265, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO23', 'SS-G4-CP-ELO8', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Display proper respectful behaviour towards others in the country', 3266, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO24', 'SS-G4-CP-ELO8', 'SS-G4-CP', 'SS', 'social-studies', 'G4', '4', 'Civic Participation', 'Appreciate that everyone has a responsibility to help develop the country.', 3267, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO25', 'SS-G4-EDM-ELO1', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Identify how access to resources of our country have shaped the country’s settlement location over time', 3268, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO26', 'SS-G4-EDM-ELO1', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Compare past and present settlements using charts and maps, focusing on how resource use, technology, and environmental changes influence these patterns', 3269, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO27', 'SS-G4-EDM-ELO1', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Appreciate that our resources impact where we settle', 3270, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO28', 'SS-G4-EDM-ELO2', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Explain the major economic activities in your country and the importance of each to the economy', 3271, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO29', 'SS-G4-EDM-ELO2', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Explain the major economic activities in your country and the importance of each to the economy', 3272, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO30', 'SS-G4-EDM-ELO2', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Chart the types of jobs associated with various industries and predict future needs for workers', 3273, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO31', 'SS-G4-EDM-ELO2', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Appreciate that our economic well-being is dependent on the sustainable use of our resources', 3274, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO32', 'SS-G4-EDM-ELO3', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Identify major uses of land and their location, such as residential, industrial, agriculture, industry, tourism', 3275, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO33', 'SS-G4-EDM-ELO3', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Map the location and distribution of various land uses in your country', 3276, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO34', 'SS-G4-EDM-ELO3', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Appreciate that geographic factors influence how land is used', 3277, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO35', 'SS-G4-EDM-ELO4', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Identify the diverse roles the ocean plays in supporting our country and understand the factors that threaten its health and sustainability.', 3278, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-ES-SCO12', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Assess potential impact of spheres on humankind', 3700, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SS-G4-CP-SCO36', 'SS-G4-EDM-ELO4', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Explore jobs and sectors in the blue economy, focusing on their impact on marine environments and how sustainable practices can reduce negative effects.', 3279, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO37', 'SS-G4-EDM-ELO4', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Appreciate how our economic activities impact the ocean which in turn impacts our economy', 3280, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO38', 'SS-G4-EDM-ELO5', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Explore how environmental issues (eg. climate change, pollution, weather systems) have a negative impact on our economy', 3281, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO39', 'SS-G4-EDM-ELO5', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Categorize the impacts of environmental issues on our economy', 3282, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO40', 'SS-G4-EDM-ELO5', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Appreciate the ways that our country is protecting the coastal and marine environment and determine additional approaches that would enhance this', 3283, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO41', 'SS-G4-EDM-ELO6', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Describe the ways that our country meets its energy needs for electricity and transportation and explore the use of renewable sources', 3284, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO42', 'SS-G4-EDM-ELO6', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Assess the impact of our current energy sources on our local and global economy and environment: The exploration of resources as a means of renewable energy', 3285, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SS-G4-CP-SCO43', 'SS-G4-EDM-ELO6', 'SS-G4-EDM', 'SS', 'social-studies', 'G4', '4', 'Economic Decision Making', 'Appreciate the value of renewable sources of energy (such as solar, wind, geothermal and hydroelectric) for our economy', 3286, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO1', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Clarify opinions by responding to the questions and ideas of others using evidence to support thinking.', 3287, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO2', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Use intonation, tone, and expression to communicate ideas and feelings in various situations considering audience and purpose.', 3288, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO3', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Discuss news, current events, opinions, feelings, strengths, challenges, future jobs, and hopes in class discussions.', 3289, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO4', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Reflect on strengths as listeners and speakers, identify areas for improvement, and evaluate helpful oral communication strategies.', 3290, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO5', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Participate as active listeners by identifying main points, determining sequence of events, giving accurate accounts, and taking notes.', 3291, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO6', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Report on a topic or text, tell a story, or recount an experience in an organized manner using relevant facts and descriptive details.', 3292, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO7', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Follow agreed-upon discussion rules and carry out assigned roles.', 3293, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO8', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Create or use visual aids such as graphics and sound to enhance presentations.', 3294, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO9', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Use appropriate facial expressions and gestures to support or dramatize messages.', 3295, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO10', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Adapt speech to different contexts and tasks using formal English when appropriate.', 3296, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO11', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Orally present an argument or perspective.', 3297, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO12', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Create and participate in mini debates or speeches using persuasive techniques.', 3298, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO13', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Identify reasons and evidence a speaker provides to support points.', 3299, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G5-LS-SCO14', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Respond to and give sequential multistep directions with increasing detail.', 3300, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO15', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Listen critically to identify persuasive techniques used in advertisements.', 3301, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO16', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Critically listen to ideas and perspectives in collaborative learning situations.', 3302, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO17', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Adjust language level to suit specific communication situations.', 3303, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO18', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Reflect critically on oral presentations and evaluate the speaker’s perspective.', 3304, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO19', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Make language choices that show sensitivity and respect for others’ ideas and experiences.', 3305, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO20', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Listen to understand and respond appropriately in various situations and for various purposes.', 3306, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO21', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Review key ideas expressed and draw conclusions based on discussion.', 3307, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO22', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Engage in self and peer reflection on accuracy of information provided or identified.', 3308, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO23', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Consider others’ responses and offer opinions supported with evidence.', 3309, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO24', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Ask questions to check understanding, stay on topic, and link comments to others’ remarks.', 3310, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO25', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Ask a speaker for clarification about subject matter.', 3311, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO26', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Speak confidently in complete sentences using appropriate intonation and courteous expression.', 3312, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO27', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Create age-appropriate media messages such as videos, podcasts, or advertisements focusing on effectiveness.', 3313, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO28', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Converse and collaborate respectfully considering cultural contexts, audience, and purpose.', 3314, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO29', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Explain ideas and opinions with supporting details and respond to questions.', 3315, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO30', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Speak clearly using appropriate volume, pitch, pace, modulation, and gestures.', 3316, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO31', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Distinguish between Standard English and nonstandard Caribbean varieties.', 3317, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO32', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Use complex sentences with specific vocabulary and style in oral presentations.', 3318, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO33', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Use figurative and metaphorical language in oral presentations.', 3319, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO34', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Interpret meanings of words in context.', 3320, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-LS-SCO35', 'LANG-G5-LS-ELO1', 'LANG-G5-LS', 'LANG', 'language-arts', 'G5', '5', 'Listening and Speaking ', 'Paraphrase portions of text read aloud or information presented in diverse media formats.', 3321, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO1', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Select engaging paper-based, digital, and visual texts for independent reading based on interests, learning needs, appropriate level of difficulty, various genres, and diverse cultures.', 3322, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO2', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Utilise background knowledge to better comprehend topics before, during, and after reading, question and analyse information, and make connections to personal experiences.', 3323, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO3', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Read widely and experience a variety of literature from the Caribbean and other cultures.', 3324, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO4', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Reflect on strengths and areas for improvement as readers while using effective reading strategies.', 3325, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO5', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Use pictures, illustrations, word structures, and text features such as table of contents, headings, glossaries, indices, and text structures to locate and verify information.', 3326, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO6', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Develop and demonstrate critical questioning strategies to analyse point of view, purpose, bias, subtle messages, and cultural perspective in visual, musical, and written texts.', 3327, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO7', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Apply problem-solving strategies to follow written multi-step instructions and reflect on learning processes.', 3328, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO8', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Use independent reading time to develop fluency, recognise quotation markers, interpret punctuation meaningfully, adjust reading rate to mood, apply word-solving strategies, and practise skimming and scanning.', 3329, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO9', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Use meaning, structure, and visual information to search, check, self-monitor, and self-correct while reading grade-appropriate texts.', 3330, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO10', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Develop understanding of how illustrations enhance mood, setting, and plot in written or visual texts.', 3331, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO11', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Foster critical thinking and appreciation for the relationship between words and images in storytelling.', 3332, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO12', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Apply higher-order thinking skills such as analysis, synthesis, inference, and application to evaluate visual and text-based information.', 3333, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO13', 'LANG-G5-RV-ELO1', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Deepen understanding of the purpose and influence of popular texts such as websites, advertisements, and social media.', 3334, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO14', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Use prior knowledge and critical thinking skills to support comprehension of grade-appropriate texts', 3335, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO15', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Demonstrate continuing ability to use a repertoire of comprehension strategies, including determining main idea, making connections, predicting, visualising, sequencing, inferring, analysing, synthesising, summarizing, questioning', 3336, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO16', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to utilize contextual clues to derive meaning from language used in a variety of genres', 3337, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO17', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Deepen the ability to make connections that promote understanding of information read and viewed across a variety of genres: text-to-self connections, text-to-text connections, text-to-world connections', 3338, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO18', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to utilize print and digital dictionaries to aid comprehension of written text across a range of genres', 3339, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO19', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Deepen and widen vocabulary through reading a range of genres, topics and work produced by a variety of authors', 3340, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO20', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Utilize with greater competence, print, digital and personal dictionaries to comprehend unfamiliar words and add them to vocabulary repertoire', 3341, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO21', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to gain vocabulary through engagement of visual and graphical presentations: movies, videos, art, posters, infographics, advertisements', 3342, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO22', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to build vocabulary through the use and application of homonyms (homophones & homographs), antonyms, synonyms', 3343, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO23', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Utilize existing knowledge of figurative devices to enhance understanding of text: similes, metaphors, onomatopoeia, personification, alliteration', 3344, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-EN-SCO-25', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Observe a picture and identify human inventions (door example)', 3875, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('LANG-G5-RV-SCO24', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to extend vocabulary through the use of words encountered in cross-curricular content', 3345, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO25', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Extend the ability to apply knowledge of word structure to read unfamiliar vocabulary: word roots, prefixes, suffixes, inflectional endings', 3346, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO26', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Demonstrate a deeper understanding of how word order impacts meaning', 3347, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO27', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to apply knowledge of how reading fluency impacts understanding', 3348, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G5-RV-SCO28', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Deepen participation in shared reading opportunities to improve fluency, guide intonation, convey the mood and intent of the text, expand vocabulary, increase comprehension', 3349, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO29', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Strengthen the awareness of how word choice and phrasing may be used to describe persons and events in positive or negative ways', 3350, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO30', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Improve their reading comprehension by confidently using background information and context clues to grasp and understand unusual words', 3351, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO31', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Improve reading comprehension and word recognition by applying knowledge of roots, prefixes, suffixes, and syllabication', 3352, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO32', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Strengthen their ability to use phonological and word analysis to decipher words, improving reading speed and accuracy: vowel patterns, common digraphs, diphthongs, complicated letter patterns, words with silent letters', 3353, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO33', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Apply background knowledge and information from poetry, expository, narrative, persuasive, and descriptive texts to make and modify predictions', 3354, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO34', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Differentiate, with greater competence, main ideas from supporting information in poetry, expository, narrative, persuasive and descriptive texts', 3355, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO35', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Demonstrate appropriate use of prior knowledge of written and visual information to form a judgment about a particular point or issue', 3356, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO36', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Exhibit a strong understanding of meaningful and critical use of text features to locate and use information: titles, subtitles, table of contents, glossary, index, etc.', 3357, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO37', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Appreciate the contribution visual components make to facilitate comprehension and promote a deeper understanding of poetry, exposition, narration, and description: fonts, charts, images, pictures, maps', 3358, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO38', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Strengthen ability to recognize and provide examples of how author’s choice of vocabulary, phrases, and sentences evoke emotions, enhance description, and create humour', 3359, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO39', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Provide examples to demonstrate how illustrators create mood in visual text', 3360, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO40', 'LANG-G5-RV-ELO2', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Utilize prior knowledge to discuss the effectiveness and possible hidden messages of emoticons and social media posts', 3361, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO41', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Continue to develop the skills to compare and contrast various formats of fiction, nonfiction, poetry, and drama', 3362, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO42', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Demonstrate growing awareness that fiction, nonfiction, and poetry reflect a purpose and a point of view', 3363, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO43', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Identify different purposes for reading from selected passages', 3364, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO44', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Describe the author’s theme/purpose and cite supporting evidence', 3365, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO45', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Respond critically to text by identifying instances where language is being used to manipulate, persuade or control', 3366, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO46', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Discuss text with reference to purpose and style of a variety of illustrators of fiction, nonfiction, and poetry: to inform, to entertain, to persuade', 3367, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO47', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Demonstrate understanding of an author’s style of plot development of fiction: fables, folk tales, fairy tales, and adventure stories — use of time sequence, use of descriptive language, use of dialogue', 3368, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO48', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Identify different genres of texts such as fiction, nonfiction, poetry, and drama and explain how each genre influences the reader''s understanding and interpretation of the text', 3369, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO49', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Recognize and analyse text features such as headings, subheadings, illustrations, and captions to understand their influence on the meaning and comprehension of the text', 3370, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO50', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Compare and contrast the use of paragraphing in fiction and nonfiction texts to understand how it impacts the organization and clarity of ideas', 3371, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO51', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Analyse stanzas and rhyme schemes in poetry to comprehend how they contribute to the overall meaning and mood of the poem', 3372, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO52', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Examine dialogue markers (e.g., said, shouted, nodded, exclaimed, etc.), scenes, and stage directions in drama to understand their role in shaping characters, conflicts, and plot development', 3373, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO53', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Generate questions based on graphical representations e.g., charts, diagrams, posters, billboards, videos, etc.', 3374, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO54', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Recognise how authors use imagery, descriptive language, and vocabulary to create the tone and mood within the text', 3375, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO55', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Analyse the purpose of messages relayed through social media platforms as agents to inform, influence, misinform, bully, entertain, etc.', 3376, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO56', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Identify examples of how an author uses and develops characters through: descriptive language, informal and formal language, Home Language(s) and Standard English, dialogue', 3377, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO57', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Recognize and interpret authors’ viewpoints through critical lens to determine the implied and explicit messages in all genres in advertisements and product labels', 3378, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO58', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Further develop understanding of an illustrator’s use of implied and explicit messages', 3379, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-RV-SCO59', 'LANG-G5-RV-ELO3', 'LANG-G5-RV', 'LANG', 'language-arts', 'G5', '5', 'Reading & Viewing', 'Recognize how vocabulary usage creates imagery and aids interpretation and understanding of text', 3380, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO1', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Generate, gather and organize ideas and information to write for an intended purpose and audience', 3381, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO2', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Reflect on and identify their strengths as writers, areas of improvement and the strategies they found most useful at different stages of the writing process', 3382, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO3', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Brainstorm content for short research projects that build knowledge about a topic', 3383, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO4', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to use personal interests or community experiences, music, books, documentaries, videos, pictures as writing prompts', 3384, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO5', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Maintain writing portfolios — drafts, revisions, personal writing prompts, etc.', 3385, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO6', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Use a variety of paper-based and digital resources to gather information to support and enhance the brainstorming process', 3386, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO7', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Examine samples of different genres as models for organizing a sequence of events, changes in setting, and character development', 3387, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO8', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Develop competence in organizing and arranging ideas and information to write for an intended purpose and audience', 3388, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO9', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Organize and strengthen writing during drafting stage', 3389, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO10', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Create and use simple paper-based or digital graphic organizers to aid the organization of ideas (e.g., five-finger plan, story map, web, list, five Ws, and graphic organizers for specific forms of writing)', 3390, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO11', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to explore and experiment with various ways to express their thoughts and ideas in various text forms (e.g., Narrative, Descriptive, Expository, Persuasive)', 3391, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO12', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to utilize strategies to organize ideas into a draft that supports the topic, enhances clarity, and sequences logically', 3392, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO13', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Demonstrate understanding by using linking words and phrases to develop a logical progression of ideas and thoughts (e.g., linking/connecting words for emphasis, contrast, reasoning, illustration, etc.)', 3393, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO14', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to explore and represent in written pieces: introductory/topic sentences, concluding sentences, paragraphs, a range of vocabulary to match the genre and purpose of the writing', 3394, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO15', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to develop purpose and use of the form of simple, compound, and complex sentences', 3395, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO16', 'LANG-G5-WR-ELO1', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Build on existing knowledge of the various genres: narrative writing, expository writing, descriptive writing, persuasive writing, poetry (rhyme, limerick, shape), book reports', 3396, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO17', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Analyse and identify different organization styles used in written drafts and representations, including narrative, descriptive, expository, persuasive structures', 3397, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO18', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Evaluate the effectiveness of organization styles within various subgenres', 3398, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('LANG-G5-WR-SCO19', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Revise written drafts to improve organization by selecting and applying appropriate organization styles based on the purpose, audience, and content of the writing', 3399, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO20', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Demonstrate proficiency in using graphic organizers, outlines, and other planning tools to structure and organize ideas effectively in written drafts', 3400, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO21', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Expand their vocabulary repertoire by identifying and incorporating a variety of precise and descriptive vocabulary words into their written drafts', 3401, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO22', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Demonstrate the ability to select appropriate synonyms and antonyms to enhance the clarity, depth, and richness of their vocabulary choices in written compositions', 3402, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO23', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Apply context clues and word analysis strategies to infer the meanings of unfamiliar vocabulary words encountered in written drafts and effectively incorporate them into their writing', 3403, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('MATH-G5-ON-SCO28', 'MATH-G5-ON-ELO5', 'MATH-G5-ON', 'MATH', 'mathematics', 'G5', '5', 'Operations with Numbers', 'Solve multi-step word problems efficiently and accurately', 2902, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('LANG-G5-WR-SCO24', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Revise and refine their written drafts by replacing generic or repetitive vocabulary with more specific and nuanced language to convey precise meanings and evoke vivid imagery', 3404, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO25', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Analyse the impact of word choice on the tone, mood, and overall effectiveness of their written compositions, making deliberate decisions to select vocabulary that aligns with the intended rhetorical purpose and audience', 3405, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO26', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Reflect on their vocabulary learning process, identifying strengths and areas for growth, and setting goals for further expanding and diversifying their vocabulary skills in future writing endeavours', 3406, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO27', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Engage in peer collaboration and feedback sessions to receive input on their vocabulary usage in written drafts, providing constructive suggestions for improvement and implementing revisions based on peer and teacher feedback', 3407, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO28', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Identify and correct grammatical errors in written drafts, including errors related to verb tense, subject-verb agreement, punctuation, and sentence structure', 3408, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO29', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Revise written drafts to enhance sentence fluency, ensuring that sentences are varied in length and structure, and flow smoothly from one to the next', 3409, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO30', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Apply knowledge of sentence-level grammar rules and conventions to improve the clarity, coherence, and readability of written compositions', 3410, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO31', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Demonstrate mastery of transitional devices and cohesive elements to connect ideas within and between sentences, paragraphs, and sections of written drafts', 3411, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO32', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Analyse the impact of different sentence structures and stylistic choices on the overall effectiveness and tone of written compositions', 3412, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO33', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Collaborate with peers to provide and receive constructive feedback on grammar and sentence fluency in written drafts, incorporating feedback to revise and improve the quality of writing', 3413, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO34', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Reflect on personal growth and development in language use, identifying areas of strength and areas for improvement in grammar and sentence fluency skills', 3414, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO35', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Apply revision strategies and techniques learned in the writing process to independently revise and polish written drafts for grammar and sentence fluency prior to final submission', 3415, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO36', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Demonstrate an enhanced ability to effectively express ideas and convey meaning through written and visual representations, employing appropriate language use, clarity, and coherence', 3416, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO37', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Understand and use formal, informal, Home Language and Standard English as appropriate to the purpose, topic, setting, plot line and characters in writing', 3417, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO38', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to engage in individual and peer revision opportunities to share drafts and provide/receive feedback on elements of grammar and sentence fluency such as: use of simple verb tenses, comparative and superlative adjectives and adverbs, form and use of possessives, subject and verb and pronoun-antecedent agreement, use of simple, compound and complex sentence patterns, determining complete and incomplete sentences', 3418, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO39', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Make use of reference material (e.g., dictionaries, glossaries, thesauruses), both print and digital, to find the pronunciation and determine or clarify the precise meaning of key words and phrases for use in their writing', 3419, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO40', 'LANG-G5-WR-ELO2', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Make use of figurative language to revise and enhance their writing (e.g., similes, metaphors, onomatopoeia, hyperbole, idioms, alliteration, etc.)', 3420, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO41', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Continue to apply learning and further develop proficiency in spelling, contributing to the overall quality of written work (affixes, synonyms, antonyms, root words)', 3421, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO42', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Transfer understanding of spelling conventions across various subjects', 3422, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO43', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Further develop self-monitoring strategies to notice and correct spelling errors', 3423, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO44', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Develop proficiency in the use of punctuation conventions, including: full stops, commas, apostrophes, and other punctuation marks as needed to accurately convey meaning and enhance the clarity of written work', 3424, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO45', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Begin to make decisions about the strategic use of punctuation, considering the potential impact on sentence structure and overall coherence of the passage', 3425, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO46', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Connect punctuation choice to decisions about style and format', 3426, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO47', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Develop the ability to choose a variety of presentation formats throughout the year based on the nature of the content and the intended audience', 3427, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO48', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Integrate visual elements, including images, charts, graphs, and other graphics, into written work to enhance overall clarity and appeal to the reader', 3428, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO49', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Publish written work for varying audiences using various tools', 3429, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO50', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Engage in collaborative projects to create and present written content using various formats', 3430, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('LANG-G5-WR-SCO51', 'LANG-G5-WR-ELO3', 'LANG-G5-WR', 'LANG', 'language-arts', 'G5', '5', 'Writing and Representing ', 'Add titles, cover images, tables of content, glossaries, book blurbs, information about the author, etc. as needed', 3431, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO1', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Define the terms: matter, compression, surface tension, particles, melting, freezing, heating, boiling, condensation, evaporation, thermal expansion and contraction, hydraulics', 3432, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO2', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Demonstrate an understanding that matter is made up of particles too small to be seen', 3433, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO3', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Understand that air is a mixture of different gases, including water vapour', 3434, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO4', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Identify the properties of air and discuss the importance of air to people', 3435, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO5', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Define surface tension and suggest ways that it can be broken', 3436, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO6', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Describe the effect of detergent on surface tension', 3437, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO7', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Give examples of surface tension in everyday life and in nature', 3438, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO8', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Describe some characteristic properties of the different states of matter', 3439, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO9', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Use the arrangement of particles in solids, liquids, and gases to explain observations made in different activities', 3440, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO10', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Distinguish between the different states of matter', 3441, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO11', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Compare different states of matter in terms of the arrangement and movement of their particles', 3442, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO12', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Describe each state of matter in terms of the arrangement of its particles', 3443, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO13', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Describe the three phases of matter (solid, liquid, gas) and give examples of each', 3444, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO14', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Identify solids, liquids and gases based on their characteristics', 3445, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO15', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Demonstrate the effects of heating and cooling on solids, liquids, and gases', 3446, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO16', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Give examples of the effects of heating and cooling on solids, liquids, and gases', 3447, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G5-SPR-SCO17', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Describe phase changes in terms of heat gain or heat loss', 3448, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO18', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Identify change of states of matter focusing on liquid changing to a solid', 3449, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO19', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Use the terms melting, evaporating, condensing, and freezing to describe phase changes', 3450, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO20', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Identify the processes (heating, melting, evaporation, condensation, freezing) that bring about a change of state of matter', 3451, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO21', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Describe the effects of compressing a gas', 3452, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO22', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Explain why it is easier to compress a gas than a liquid in terms of the arrangement of their particles', 3453, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO23', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Explain how dissolving substances in water supports the theory that matter is made up of particles too small to be seen', 3454, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO24', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Use a model to describe the differences in attraction among the particles of a solid, liquid, and gas', 3455, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO25', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Label drawings of different phases of matter by their properties of shape and volume', 3456, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO26', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Observe and describe phenomena involving gases and use these to create a model of a gas', 3457, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO27', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Develop a model to describe that matter is made up of tiny particles, too small to be seen', 3458, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO28', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Use a model to describe the evaporation of water from a solution to produce salt crystals', 3459, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO29', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Use models to demonstrate the behaviour of particles in different states of matter', 3460, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO30', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Conduct experiments to observe changes in matter (e.g., dissolving sugar, compressing air)', 3461, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
  ('SCIENCE-G5-SPR-SCO31', 'SCIENCE-G5-SPR-ELO1', 'SCIENCE-G5-SPR', 'SCIENCE', 'science', 'G5', '5', 'Structure and Properties of Matter ', 'Observe changes in matter that provide evidence that matter is made up of small particles that cannot be seen', 3462, '[]'::jsonb, '2026-02-21T17:24:25.155012+00:00'),
