INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G5-ES-SCO8', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Research how earth events can affect earth sphere systems.', 3696, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO9', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Investigate how volcanoes and hurricanes can impact earth sphere systems.', 3697, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO10', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Compare the impact of mountain ranges on wind patterns and cloud formation by constructing a model that demonstrates how these landforms influence atmospheric conditions and local climates.', 3698, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO11', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Interpret models of earth systems.', 3699, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO13', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Classify components of earth’s systems as geosphere, atmosphere, biosphere and hydrosphere.', 3701, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO14', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Communicate their understand through models, written work and presentations', 3702, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO15', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Predict how changes to one earth system affect another.', 3703, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO16', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Construct graphic organizers that compare sphere interaction.', 3704, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO17', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Investigate how human interactions impact earth systems', 3705, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO18', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate an understanding that the spheres work together and it is our responsibility to care for our earth systems.', 3706, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
