  ('SCIENCE-G5-ES-SCO20', 'SCIENCE-G5-ES-ELO1', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Consistently ask questions and clarifications during investigations including questions that exhibit the desire to do follow up activities', 3708, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
