  ('SCIENCE-G5-ES-SCO51', 'SCIENCE-G5-ES-ELO2', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Collaboration & Cooperation within group activities.', 3739, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO52', 'SCIENCE-G5-ES-ELO2', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Stewardship/Respect for Living Things', 3740, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO53', 'SCIENCE-G5-ES-ELO2', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Safety in using tools and processes for building models', 3741, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO54', 'SCIENCE-G5-ES-ELO2', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 3742, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO55', 'SCIENCE-G5-ES-ELO2', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Participate actively in classroom discussions.', 3743, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO56', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Define the terms: Polluting, Environment, Conservation, Turbid, Reservoirs, Water diary, Consumption,Atmosphere, Humid, Acid rain, Environmental destruction. Clean air,  Environmental activists, Scrub, Solid waste, Industrial effluent, Fracking, Phosphate detergents, Plastic recycling, Fossil fuels', 3744, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO57', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'State properties of clean air and describe conditions of air e.g. hot, cold, sticky. (ST 1 ESS ER 4) ', 3745, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO58', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Define the term solid waste, identifying methods of managing this waste in home/school/community (recycling, composting etc.) (ST 2 LS ECS 23)', 3746, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G5-ES-SCO59', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', ' Define the term environmental destruction and investigate the factors that cause and prevent this destruction. (ST 2 LS ECS 24)', 3747, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO60', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', ' Identify the role of recycling and other named conservation methods in the maintenance of a balanced environment. (ST 3 LS ECS 6) ', 3748, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO61', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate awareness that sustainable use of resources would help to minimize pollution and destruction of the environment. (ST 3 STSE 1) ', 3749, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO62', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Describe correct methods of garbage disposal. (ST 5 ESS ER 3)', 3750, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO63', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Identify that air is needed for burning, and describe how the process works. (ST 5 ESS ER 7)', 3751, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO64', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Explain the importance of ''clean'' air in their country. (ST 5 ESS ER 11)', 3752, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO65', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Identify and name natural sources of water. (ST 5 ESS ER 12)', 3753, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO66', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Describe, with examples, the effects of water shortage in the environment and human activity. (ST 5 ESS ER 13)', 3754, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO67', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Identify and describe how water may be polluted, and how human activities help in this situation. (ST 5 ESS ER 14)', 3755, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO68', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Identify and name marine pollutants, explaining how each damages the environment. (ST 5 LS ECS 7)', 3756, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO69', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Describe how human activities may result in air and water pollution. (ST 5 LS ECS 8)', 3757, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO70', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Describe different methods of disposing of solid waste materials and demonstrate most appropriate methods of disposal. (ST 6 ESS ER 1)', 3758, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO71', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Describe and discuss how burning can cause air pollution. (ST 6 ESS ER 4)', 3759, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO72', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'List and explain which activities of humans may affect the water supply and pollute our scarce resources. (ST 6 ESS ER 8)', 3760, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO73', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Discuss ways of preventing and reducing water pollution. (ST 6 ESS ER 9)', 3761, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO74', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Compare pro and con opinions on contentious issues (e.g. fracking)', 3762, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO75', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Compare clean and dirty water.', 3763, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO76', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Distinguish clean and polluted air.', 3764, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO77', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Explain how acid rain is created by industry.', 3765, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO78', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Explain to their classmates the need for environmental conservation in their country, outlining possible scenarios if such protection is neglected. (ST 3 LS ECS 7)', 3766, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO79', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Classify litter as recyclable and non-recyclable. (ST 5 ESS ER 4)', 3767, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO80', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Plan and participate in clean-up drive in their school. (ST 5 ESS ER 5)', 3768, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO81', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Design, construct and use discarded materials to make useful items. (ST 5 ESS ER 6)', 3769, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO82', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Compare devices that burn different fuels from the amount of pollution they cause. (ST 5 ESS ER 8)', 3770, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO83', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Compare the amount of air pollution in two named areas. (ST 5 ESS ER 9)', 3771, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO84', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Hypothesize as to the reasons for the differences exhibited in ST 5 ESS-ER 9 above (ST 5 ESS ER 10)', 3772, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO85', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Classify litter, using actual examples, as recyclable and non-recyclable. (ST 6 ESS ER 2)', 3773, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO86', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Design and construct a device to detect air pollution. (ST 6 ESS ER 5)', 3774, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO87', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Investigate the amount of air pollution found in two distinctly different areas and suggest a ''theory'' to account for the reasons for the differences. (ST 6 ESS ER 6)', 3775, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO88', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Design, construct and demonstrate the use of a device to determine the turbidity of water. (ST 6 ESS ER 10)', 3776, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO89', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Investigate ways in which polluted water can be made clean. (ST 6 ESS ER 11)', 3777, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO90', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Interpret information passages.', 3778, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO91', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Infer from pictures the environmental concerns.', 3779, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO92', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Use graphic organizers to clarify terminology.', 3780, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO93', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Research modes of pollution.', 3781, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO94', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Complete inventories of water usage. (consumption)', 3782, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO95', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Perform water filtering experiments.', 3783, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO96', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Perform air pollution detection experiments.', 3784, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO97', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Construct graphs from data.', 3785, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO98', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Interpret graphical information.', 3786, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO99', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate awareness that unplanned scientific and technological activities may impact humans and the environment in such a way that there is little to leave behind for succeeding generations. (ST 1 STSE 4)', 3787, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO100', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate awareness that unplanned and excessive Science and Technological activities may destroy the earth as we know it, resulting in untold disasters. (fracking, oil exploration, global warming etc.). (ST 2 STSE 2)', 3788, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO101', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate awareness that humans must realise that in their attempts to understand the world and exploit the environment to fulfil their needs there are consequences. (ST 2 STSE 1)', 3789, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO102', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate awareness that the real impact of scientific and technological activities may take years to be seen. (ST 4 STSE 2)', 3790, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO103', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate an understanding that human production processes make goods and products which may impact the environment. (ST 5 PS MM 4)', 3791, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO104', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate an understanding that humans desire to acquire understanding and to produce materials for their needs, and there may be consequences not anticipated. (ST 5 TE UT 1)', 3792, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO105', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Appreciate that the earth’s water and air resources are sensitive to the abuse of humans.', 3793, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO106', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate interest/curiosity to sample human habits like water consumption.', 3794, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO107', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Demonstrate an attitude of inquiry into new technologies that might impact the overall health of the earth.', 3795, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-ES-SCO108', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'When conducting practical and group work, display sensitivity and offer assistance to peers who may have physical or learning challenges.', 3796, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00');
INSERT INTO curriculum_spine_scos (id, elo_id, strand_id, subject_id, subject_slug, grade_id, grade_level, strand_name, sco_text, sco_order, integrated_units, created_at) VALUES
  ('SCIENCE-G5-ES-SCO109', 'SCIENCE-G5-ES-ELO3', 'SCIENCE-G5-ES', 'SCIENCE', 'science', 'G5', '5', 'Earth Systems ', 'Participate actively in classroom discussions.', 3797, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-1', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Define the terms: EARTH, FORCE, GRAVITATIONAL FORCE, GRAVITY, INVISIBLE, MASS, VELOCITY, ACCELERATION, AIR RESISTANCE, SURCAFE AREA, TIDES', 3798, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-2', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Demonstrate that the force of gravity pulls objects towards the earth.', 3799, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-3', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Compare the effects of gravity on the rate at which an object falls.', 3800, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-4', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Show that the bigger the object, the bigger that force of attraction that draws other objects to it.', 3801, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-5', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Explain the effects of air resistance on the shape of an object as it falls.', 3802, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-6', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Account for the difference in gravity between earth and moon', 3803, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-7', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Observe that gravity prevents objects from floating off into space.', 3804, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-8', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Infer what will happen if two objects of the same size and shape, one empty and filled are released from the same height.', 3805, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-9', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Predict the direction an object will go when dropped.', 3806, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-10', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Construct different parachutes and discuss which one will reach the ground first when dropped.', 3807, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
