  ('SCIENCE-G5-SSS-SCO-15', 'SCIENCE-G5-SSS-ELO1', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'When conducting practical and group work, display sensitivity and help peers who may have physical or learning challenges.', 3812, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-16', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Define the terms: STAR, SUN, REFRACTION, ALPHA CENTAURI, LIGHT YEAR, BRIGHTNESS, LUMINOSITY', 3813, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-17', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Demonstrate an understanding that the sun is considered a star', 3814, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-18', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Explain why we need the concept of a light year.', 3815, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-19', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Identify the nearest star to Earth', 3816, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-20', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Explain how distance affects the apparent brightness of a star', 3817, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-21', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Infer that the brightness of a light is affected by the distance the light must travel', 3818, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
