  ('SCIENCE-G5-SSS-SCO-26', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Create a model of a constellation', 3823, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-27', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Inquire into the names and relative distances of the nearest stars to Earth', 3824, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
