  ('SCIENCE-G5-SSS-SCO-30', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'When conducting practical and group work, display sensitivity and help peers who may have physical or learning challenges.', 3827, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-31', 'SCIENCE-G5-SSS-ELO2', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Participate actively in classroom discussions.', 3828, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-32', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Define the terms: SHADOW, ROTATION, AXIS, DAY AND NIGHT, STAR, ORBIT', 3829, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
