  ('SCIENCE-G5-SSS-SCO-34', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Explain how the position of the sun relative to the earth influences day and night.', 3831, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
