  ('SCIENCE-G5-SSS-SCO-37', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Classify bodies in the solar system as stars, constellations, and planets', 3834, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
