  ('SCIENCE-G5-SSS-SCO-39', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Observe the change in the seasonal appearance of some stars in the sky', 3836, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-40', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Infer the relationship between the sun''s position relative to the earth and the length and direction of shadows', 3837, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-41', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Construct a model to show how the earth’s rotation affects the occurrence of day and night', 3838, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-42', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Construct a model to show how the earth’s rotation affects the appearance of shadows', 3839, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-43', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Construct a graph to show the daily changes in the length and direction of shadows over a specified period', 3840, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-44', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Analyse graphical data representing daily changes in length and direction of shadows', 3841, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-45', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Analyse graphical data representing seasonal changes of stars in the night’s sky', 3842, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-SSS-SCO-46', 'SCIENCE-G5-SSS-ELO3', 'SCIENCE-G5-SSS', 'SCIENCE', 'science', 'G5', '5', 'Stars and the Solar Systems', 'Account for the change in the occurrence of constellations using a model of the earth’s orbit around the sun.', 3843, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
