  ('SCIENCE-G5-EN-SCO-2', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Demonstrate with a picture that they understand the difference between first-, second- and third-class levers.', 3852, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-3', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Compare electrical circuits that will generate light and those that won’t.', 3853, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
