  ('SCIENCE-G5-EN-SCO-5', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Give examples of devices that operate by direct current.', 3855, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-6', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Account for how a switch controls whether a device is able to operates by dc/ac.', 3856, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-7', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Explain with a diagram how a lever can solve a problem.', 3857, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
