  ('SCIENCE-G5-EN-SCO-10', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Identify and describe simple mechanical devices (hinges, screws, screw drivers) (ST 2 PS FMS 4)', 3860, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-11', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Realise the importance of safety in handling tools an making gadgets. (ST 2 TE NT 3)', 3861, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-12', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Formulate problems and do research in development of technological devices. e.g. construct models and gadgets. (ST 3 TE TM 1)', 3862, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-13', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Identify and explain the ways in which strengthening mechanisms are used to resist stress in structures under load. E.g. struts to resists compression, ties to resists tension. (ST 4 PS FMS 7)', 3863, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-14', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Identify and describe how forces can alter shapes of objects. E.g. bending, stretching, pulling, twisting. (ST 4 PS FMS 8)', 3864, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-15', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Explain how ties can be used in roof construction to mitigate the effects of strong winds.', 3865, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-16', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Identify and name parts of a simple circuit and demonstrate by setting one up. (ST 5 PS EN 1)', 3866, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-17', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Distinguish giving examples, the differences between conductors and insulators. (ST 5 PS EN 2)', 3867, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-18', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Name the instrument used to measure force and the unit in which it is measured. (ST 5 PS FMS 1)', 3868, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-19', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Identify a number of common levers and describe how they operate to make work easier. (ST 5 PS FMS 3)', 3869, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-20', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Name the points of a lever giving some common examples. (ST 5 PS FMS 4)', 3870, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
  ('SCIENCE-G5-EN-SCO-21', 'SCIENCE-G5-EN-ELO1', 'SCIENCE-G5-EN', 'SCIENCE', 'science', 'G5', '5', 'Engineering', 'Identify the main parts of a wheel and an axle giving examples and describing how the objects function. (ST 5 PS FMS 5)', 3871, '[]'::jsonb, '2026-02-21T17:24:25.449172+00:00'),
