  ('SS-G5-HCT-SCO1', 'SS-G5-HCT-ELO1', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Explain the advantages and disadvantages of different forms of communication technology', 3173, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO2', 'SS-G5-HCT-ELO1', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Determine the appropriate form of communication technology for different situations over time.', 3174, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO3', 'SS-G5-HCT-ELO1', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Recognise the need for proper etiquette when using social media', 3175, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO4', 'SS-G5-HCT-ELO2', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Discuss the role of the media in our society. And outline how it evolved', 3176, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO5', 'SS-G5-HCT-ELO2', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Demonstrate skills in determining facts and opinions when using various mediums of communication', 3177, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO6', 'SS-G5-HCT-ELO2', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Appreciate the need to critically analyse information in the media', 3178, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO7', 'SS-G5-HCT-ELO3', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Identify the settlement patterns of Europeans in the Lesser and Greater Antilles from the 1400s - 1800s', 3179, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO8', 'SS-G5-HCT-ELO3', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Examine how the Caribbean was negatively and positively affected by European colonisation', 3180, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO9', 'SS-G5-HCT-ELO3', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Recognize that colonisation had lasting effects on the Caribbean', 3181, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO10', 'SS-G5-HCT-ELO4', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Explain why colonial powers brought enslaved Africans to the Caribbean in the 1600s-1800s', 3182, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO11', 'SS-G5-HCT-ELO4', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Map the route of the triangular slave trade', 3183, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO12', 'SS-G5-HCT-ELO4', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Develop an awareness of how the introduction of Africans as slaves has impacted our (economic, cultural, and political) history', 3184, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO13', 'SS-G5-HCT-ELO5', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Identify the ways that enslaved Africans in the Caribbean resisted bondage', 3185, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO14', 'SS-G5-HCT-ELO5', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Categorise the forms of resistance into everyday actions and armed rebellion', 3186, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-HCT-SCO15', 'SS-G5-HCT-ELO5', 'SS-G5-HCT', 'SS', 'social-studies', 'G5', '5', 'Historical and Cultural Thinking', 'Recognise that resistance to enslavement took great courage and required cooperation', 3187, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO1', 'SS-G5-ST-ELO1', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Describe various classifications of the Caribbean region such as Bahamas, Greater and Lesser Antilles, Windward and Leeward Islands, and Caribbean coastal areas (mainland territories)', 3188, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO2', 'SS-G5-ST-ELO1', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Plot on a map linguistic, political, and economic information for each classification of the Caribbean', 3189, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO3', 'SS-G5-ST-ELO1', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Appreciate that the location of the different islands/ territories brought about differing positive and negative consequences for their people', 3190, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO4', 'SS-G5-ST-ELO2', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Describe the geographic differences between coral and volcanic island formations', 3191, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO5', 'SS-G5-ST-ELO2', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Explain the impact of different island types on the economy and people’s way of life', 3192, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO6', 'SS-G5-ST-ELO2', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Appreciate that both volcanic and coral islands hold environmental and economic benefits and pose challenges', 3193, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO7', 'SS-G5-ST-ELO3', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Identify popular/ major landmarks (natural and built) in the region', 3194, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO8', 'SS-G5-ST-ELO3', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Map the location of important landmarks in the region', 3195, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO9', 'SS-G5-ST-ELO3', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Appreciate the value (economic, cultural, historical) of familiar landmarks to the development of the region', 3196, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO10', 'SS-G5-ST-ELO4', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Describe climatic differences across the Caribbean', 3197, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO11', 'SS-G5-ST-ELO4', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Plot the coordinates of various islands and display differences in temperature and rainfall', 3198, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO12', 'SS-G5-ST-ELO4', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Appreciate the importance of climate and climate changes for shaping the economy, and society, and policy decisions of various areas of the Caribbean', 3199, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO13', 'SS-G5-ST-ELO5', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Identify how climatic similarities and severe weather events associated with climate change have fostered cooperation (E.g. Leeward islands and freshwater)', 3200, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO14', 'SS-G5-ST-ELO5', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Plot major climatic disasters in the region over the past 50 years and note changes related to climate change and assess their negative effects', 3201, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-ST-SCO15', 'SS-G5-ST-ELO5', 'SS-G5-ST', 'SS', 'social-studies', 'G5', '5', 'Spatial Thinking', 'Assess the ways that Caribbean countries have assisted one another in recent climate disasters especially as it has related to climate change', 3202, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO1', 'SS-G5-CP-ELO1', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'Identify the various other types of government systems in the region', 3203, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO2', 'SS-G5-CP-ELO1', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'Compare the structures of the main types of government systems in the region', 3204, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO3', 'SS-G5-CP-ELO1', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'Appreciate that democratic systems of government can have varying structures', 3205, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO4', 'SS-G5-CP-ELO2', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'State the reasons for regional integration with other Caribbean countries', 3206, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO5', 'SS-G5-CP-ELO2', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'Research different areas of integration in the Caribbean', 3207, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO6', 'SS-G5-CP-ELO2', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'Appreciate that there are both advantages and limitations of regional integration and interaction', 3208, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00'),
  ('SS-G5-CP-SCO7', 'SS-G5-CP-ELO3', 'SS-G5-CP', 'SS', 'social-studies', 'G5', '5', 'Civic Participation', 'List regional organizations that have shaped the Caribbean region and state the main objectives', 3209, '[]'::jsonb, '2026-02-21T17:24:25.77614+00:00');
