  ('LANG-G4-WR-SCO14', 'LANG-G4-WR-ELO1', 'LANG-G4-WR', 'LANG', 'language-arts', 'G4', '4', 'Writing and Representing', 'apply knowledge of subject verb agreement within sentence structure to notice areas or writing requiring revision ', 2725, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
