  ('SCIENCE-G4-E-SCO25', 'SCIENCE-G4-E-ELO1', 'SCIENCE-G4-E', 'SCIENCE', 'science', 'G4', '4', 'Energy', 'Appreciate that the relationship between motion and energy can be seen in everyday activities and the environment.', 2766, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
  ('LANG-G4-WR-SCO19', 'LANG-G4-WR-ELO1', 'LANG-G4-WR', 'LANG', 'language-arts', 'G4', '4', 'Writing and Representing', 'continue to engage in individual and peer revision opportunities to share drafts and provide/ receive feedback on elements of grammar and sentence fluency such as: 
