  ('LANG-G4-WR-SCO20', 'LANG-G4-WR-ELO2', 'LANG-G4-WR', 'LANG', 'language-arts', 'G4', '4', 'Writing and Representing', 'continue to apply learning and further develop proficiency in spelling, contributing to the overall quality of written work ', 2731, '[]'::jsonb, '2026-02-21T17:24:24.495614+00:00'),
